#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,m,len[N*4];
double a[N],mx[N*4];
void pushup1(int u)
{
	mx[u]=max(mx[u*2],mx[u*2+1]);
}
int pushup2(double tmp,int u,int l,int r)
{
//	cout<<"aaa "<<tmp<<" "<<u<<" "<<l<<" "<<r<<"\n";
	if(mx[u]<=tmp)
	{
		return 0;
	}
	if(a[l]>tmp) return len[u];
	if(l==r) return a[l]>tmp;
	int ls=u*2,rs=u*2+1,mid=(l+r)/2;
//	cout<<"nxt "<<tmp<<"\n";
	if(mx[ls]<=tmp) return pushup2(tmp,rs,mid+1,r);
	else return pushup2(tmp,ls,l,mid)+len[u]-len[ls];
}
void update(int u,int l,int r,int x,int y)
{
//	cout<<u<<" "<<l<<" "<<r<<" "<<x<<" "<<y<<"\n";
	if(l==r&&l==x)
	{
		mx[u]=(double)y/x;
		len[u]=1;
		return ;
	}
	int mid=(l+r)/2;
//	cout<<"a "<<x<<" "<<mid<<"\n";
	if(x<=mid) update(u*2,l,mid,x,y);
	else if(x>mid) update(u*2+1,mid+1,r,x,y);
	pushup1(u);
//	cout<<"up2 :"<<mx[u*2]<<"\n";
	len[u]=len[u*2]+pushup2(mx[u*2],u*2+1,mid+1,r);
//	cout<<len[u]<<"\n";
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
//		cout<<i<<" ____________\n";
		int x,y;
		cin>>x>>y;
		a[x]=(double)y/x;
//		cout<<a[x]<<"\n";
		update(1,1,n,x,y);
		cout<<len[1]<<"\n";
	}
	return 0;
}
